#!/usr/bin/env python# -*- coding:utf-8 -*-# @Time : 2026/4/7# @Author : cyq# @File : interfaceTaskController# @Software: PyCharm# @Desc:from fastapi import APIRouter, Dependsfrom app.mapper.interfaceApi.interfaceTaskMapper import InterfaceTaskMapperfrom app.schema.api.interfaceTaskSchema import (    InsertInterfaceTaskSchema,UpdateInterfaceTaskSchema,OptTaskSchema,PageInterfaceTaskSchema)from app.controller import Authenticationfrom app.model.base import Userfrom app.response import Responserouter = APIRouter(prefix="/interface/task", tags=['自动化接口步骤'])@router.post('/insertTask', description="创建任务")async def insert_task(taskInfo: InsertInterfaceTaskSchema,                      creator_user: User = Depends(Authentication())):    task = await InterfaceTaskMapper.insert_task(        user=creator_user,        **taskInfo.model_dump(            exclude_unset=True,            exclude_none=True        )    )    return Response.success(task)@router.post("/updateTask", description="修改")async def update_task(update: UpdateInterfaceTaskSchema,                      updater: User = Depends(Authentication())):    task = await InterfaceTaskMapper.update_task(        update_user=updater,        **update.model_dump(exclude_unset=True,                            exclude_none=True)    )    return Response.success(task)@router.get("/basic", description="任务详情")async def get_task_detail(task_id:int,                          _: User = Depends(Authentication())):    task = await InterfaceTaskMapper.get_by_id(ident=task_id)    return Response.success(task)@router.post("/removeTask", description='删除任务')async def removeTask(task: OptTaskSchema, _: User = Depends(Authentication())):    await InterfaceTaskMapper.delete_by_id(taskId=task.task_id)    return Response.success()@router.post("/page", description="任务分页")async def pageTask(pageInfo: PageInterfaceTaskSchema, _=Depends(Authentication())):    tasks = await InterfaceTaskMapper.page_by_module(**pageInfo.model_dump(        exclude_unset=True,        exclude_none=True    ))    return Response.success(tasks)# --- 关联